import React, { useEffect, useState } from "react";

const buttonRow = { display: "flex", gap: "0.5rem", marginBottom: "1rem" };

export default function Dashboard({ onSelectEvent }) {
  const [events, setEvents] = useState([]);
  const [filter, setFilter] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    const query = filter ? `?filter=${filter}` : "";
    fetch(`/api/events${query}`)
      .then((res) => res.json())
      .then(setEvents)
      .catch(() => setError("Failed to load events"));
  }, [filter]);

  return (
    <section>
      <h2>Event Dashboard</h2>
      <div style={buttonRow}>
        <button onClick={() => setFilter("")}>All</button>
        <button onClick={() => setFilter("upcoming")}>Upcoming</button>
        <button onClick={() => setFilter("ongoing")}>Ongoing</button>
        <button onClick={() => setFilter("past")}>Past</button>
      </div>
      {error && <p>{error}</p>}
      {events.length === 0 && !error && <p>No events found.</p>}
      <ul>
        {events.map((event) => (
          <li key={event._id} style={{ marginBottom: "1rem" }}>
            <strong>{event.title}</strong> ({event.status})
            <div>{event.location}</div>
            <div>Fee: INR {event.fee || 0}</div>
            <button onClick={() => onSelectEvent(event)}>Register</button>
          </li>
        ))}
      </ul>
    </section>
  );
}
